surface_task_screen.content:
function renderTaskList() {
    taskListContainer.innerHTML = '';
    if (taskList.length === 0) {
        taskListContainer.innerHTML = '<p>No tasks yet — add one above</p>';
    } else {
        taskList.forEach((task, index) => {
            const card = document.createElement('div');
            card.classList.add('task-card', task.completed ? 'completed' : '');
            card.innerHTML = `
                <span>${task.title}</span>
                <input type="checkbox" ${task.completed ? 'checked' : ''} onclick="completeTask(${index})">
                <span>${task.date.toLocaleString()}</span>
            `;
            taskListContainer.appendChild(card);
        });
    }
}

